import React, { useMemo } from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip as RechartsTooltip, BarChart, Bar, XAxis, YAxis } from 'recharts';
import { format, parseISO, subDays } from 'date-fns';
import { TrendingUp, Wallet, ArrowDownRight } from 'lucide-react';
import { cn } from '../utils/cn';

const COLORS = ['#3525cd', '#006c49', '#4f46e5', '#6cf8bb', '#1b1b24'];

export default function Dashboard({ expenses }) {
  const totalSpend = useMemo(() => {
    return expenses.reduce((acc, curr) => acc + Number(curr.amount), 0);
  }, [expenses]);

  const categoryData = useMemo(() => {
    const acc = {};
    expenses.forEach(e => {
      acc[e.category] = (acc[e.category] || 0) + Number(e.amount);
    });
    return Object.entries(acc).map(([name, value]) => ({ name, value })).sort((a, b) => b.value - a.value);
  }, [expenses]);

  const trendData = useMemo(() => {
    const last7Days = Array.from({length: 7}, (_, i) => {
      const d = subDays(new Date(), i);
      return format(d, 'MMM dd');
    }).reverse();

    const data = last7Days.map(date => ({ date, amount: 0 }));

    expenses.forEach(e => {
      const eDate = format(parseISO(e.date), 'MMM dd');
      const idx = data.findIndex(d => d.date === eDate);
      if (idx !== -1) {
        data[idx].amount += Number(e.amount);
      }
    });
    return data;
  }, [expenses]);

  return (
    <div className="space-y-6">
      {/* Top Value Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="bg-gradient-to-br from-primary to-primary-container p-8 rounded-3xl shadow-ambient text-white relative overflow-hidden group">
          <div className="absolute top-0 right-0 w-64 h-64 bg-white opacity-5 rounded-full blur-3xl -mx-10 -my-10 group-hover:scale-110 transition-transform duration-500"></div>
          <p className="text-primary-fixed-dim text-sm font-semibold uppercase tracking-wider mb-2">Total Expenses</p>
          <h3 className="text-5xl font-manrope font-bold">${totalSpend.toFixed(2)}</h3>
        </div>

        <div className="bg-surface-container-lowest p-8 rounded-3xl shadow-ambient border border-surface-container-high transition-colors hover:bg-surface-bright flex flex-col justify-center">
          <div className="flex items-center gap-4">
            <div className="p-4 bg-surface-container-low rounded-2xl text-secondary">
              <TrendingUp className="w-8 h-8" />
            </div>
            <div>
               <p className="text-on-surface-variant font-medium text-sm mb-1 uppercase tracking-wide">30-Day Trend</p>
               <div className="flex items-baseline gap-2">
                 <span className="text-3xl font-manrope font-bold text-on-surface">+12%</span>
                 <span className="text-tertiary text-sm flex items-center font-medium"><ArrowDownRight className="w-4 h-4"/> vs last month</span>
               </div>
            </div>
          </div>
        </div>
      </div>

      {/* Charts */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 bg-surface-container-lowest p-6 rounded-3xl shadow-ambient border border-surface-container-high hover:bg-surface-bright transition-colors">
          <h4 className="text-lg font-manrope font-semibold mb-6 text-on-surface">Weekly Spending Trend</h4>
          <div className="h-64 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={trendData}>
                <XAxis dataKey="date" axisLine={false} tickLine={false} tick={{fill: '#777587', fontSize: 12}} />
                <YAxis hide />
                <RechartsTooltip 
                  cursor={{fill: '#f5f2ff'}}
                  contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 30px rgba(0,0,0,0.08)' }} 
                />
                <Bar dataKey="amount" fill="#4f46e5" radius={[6, 6, 6, 6]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="lg:col-span-1 bg-surface-container-lowest p-6 rounded-3xl shadow-ambient border border-surface-container-high hover:bg-surface-bright transition-colors">
          <h4 className="text-lg font-manrope font-semibold mb-6 text-on-surface">Category Split</h4>
          {categoryData.length > 0 ? (
            <div className="h-64 w-full">
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={categoryData}
                    cx="50%"
                    cy="50%"
                    innerRadius={60}
                    outerRadius={85}
                    paddingAngle={5}
                    dataKey="value"
                    stroke="none"
                  >
                    {categoryData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                    ))}
                  </Pie>
                  <RechartsTooltip 
                      contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 30px rgba(0,0,0,0.08)' }} 
                  />
                </PieChart>
              </ResponsiveContainer>
            </div>
          ) : (
            <div className="h-64 flex items-center justify-center text-on-surface-variant opacity-70">
              <p>No data yet.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
